t.script:
                        function formatCFA(value) {
                            return new Intl.NumberFormat('fr-FR', {
                                style: 'currency',
                                currency: 'XOF',
                                maximumFractionDigits: 0,
                            }).format(value);
                        }

                        function loadDashboard(dateFrom, dateTo) {
                            var data = {
                                params: {
                                    date_from: dateFrom || '',
                                    date_to: dateTo || '',
                                },
                            };
                            $.ajax({
                                url: '/resto/dashboard/data',
                                type: 'POST',
                                contentType: 'application/json',
                                data: JSON.stringify(data),
                                success: function (result) {
                                    renderDashboard(result);
                                },
                                error: function () {
                                    $('#resto-dashboard').prepend(
                                        '
Erreur de chargement du tableau de bord.'
                                    );
                                },
                            });
                        }

                        var revenueChart = null;
                        var categoriesChart = null;
                        var marginsChart = null;

                        function renderDashboard(data) {
                            $('#kpi-revenue').text(formatCFA(data.total_revenue));
                            $('#kpi-avg-ticket').text(formatCFA(data.avg_ticket));
                            $('#kpi-pos-products').text(data.pos_products_count);
                            $('#kpi-low-stock').text(data.tracked_low_stock);

                            $('#today-orders').text(data.today_orders_count);
                            $('#today-revenue').text(formatCFA(data.today_revenue));

                            var sessions = data.open_sessions || [];
                            $('#open-sessions-count').text(sessions.length);
                            if (sessions.length) {
                                var html = '';
                                sessions.forEach(function (s) {
                                    html += '
';
                                    html += '' + s.name + '';
                                    html += '' + s.config + '';
                                    html += '';
                                });
                                $('#open-sessions-list').html(html);
                            } else {
                                $('#open-sessions-list').html('
Aucune session ouverte.');
                            }

                            // Revenue chart
                            var sales = data.sales_by_day || [];
                            var revCtx = document.getElementById('chart-revenue').getContext('2d');
                            if (revenueChart) revenueChart.destroy();
                            if (sales.length) {
                                $('#no-sales-msg').addClass('d-none');
                                revenueChart = new Chart(revCtx, {
                                    type: 'line',
                                    data: {
                                        labels: sales.map(function (s) { return s.label; }),
                                        datasets: [{
                                            label: 'CA',
                                            data: sales.map(function (s) { return s.revenue; }),
                                            borderColor: '#4f7c6a',
                                            backgroundColor: 'rgba(79,124,106,0.1)',
                                            fill: true,
                                            tension: 0.3,
                                        }],
                                    },
                                    options: {
                                        responsive: true,
                                        maintainAspectRatio: false,
                                        plugins: { legend: { display: false } },
                                        scales: {
                                            y: { beginAtZero: true, ticks: { callback: function (v) { return formatCFA(v); } } },
                                        },
                                    },
                                });
                            } else {
                                $('#no-sales-msg').removeClass('d-none');
                                revenueChart = new Chart(revCtx, { type: 'line', data: { labels: [], datasets: [] } });
                            }

                            // Categories chart
                            var cats = data.category_distribution || [];
                            var catCtx = document.getElementById('chart-categories').getContext('2d');
                            if (categoriesChart) categoriesChart.destroy();
                            var catColors = ['#4f7c6a', '#d79b2b', '#c95d4f', '#3d6272', '#7c6f64'];
                            categoriesChart = new Chart(catCtx, {
                                type: 'doughnut',
                                data: {
                                    labels: cats.map(function (c) { return c.name; }),
                                    datasets: [{
                                        data: cats.map(function (c) { return c.value; }),
                                        backgroundColor: catColors,
                                    }],
                                },
                                options: {
                                    responsive: true,
                                    maintainAspectRatio: false,
                                    plugins: { legend: { display: false } },
                                },
                            });
                            var legendHtml = '';
                            cats.forEach(function (c, i) {
                                legendHtml += '
';
                                legendHtml += '' + c.name + '';
                                legendHtml += '' + c.value + '';
                                legendHtml += '';
                            });
                            $('#category-legend').html(legendHtml);

                            // Margins chart
                            var margins = data.top_margins || [];
                            var margCtx = document.getElementById('chart-margins').getContext('2d');
                            if (marginsChart) marginsChart.destroy();
                            marginsChart = new Chart(margCtx, {
                                type: 'bar',
                                data: {
                                    labels: margins.map(function (m) { return m.code; }),
                                    datasets: [{
                                        label: 'Marge %',
                                        data: margins.map(function (m) { return m.margin; }),
                                        backgroundColor: '#d79b2b',
                                    }],
                                },
                                options: {
                                    responsive: true,
                                    maintainAspectRatio: false,
                                    plugins: { legend: { display: false } },
                                    scales: {
                                        y: { beginAtZero: true, ticks: { callback: function (v) { return v + '%'; } } },
                                    },
                                },
                            });
                        }

                        $(document).ready(function () {
                            var today = new Date().toISOString().slice(0, 10);
                            $('#filter-date-from').val(today);
                            $('#filter-date-to').val(today);

                            loadDashboard(today, today);

                            $('#btn-refresh').click(function () {
                                loadDashboard($('#filter-date-from').val(), $('#filter-date-to').val());
                            });
                            $('#btn-filter-today').click(function () {
                                var t = new Date().toISOString().slice(0, 10);
                                $('#filter-date-from').val(t);
                                $('#filter-date-to').val(t);
                                loadDashboard(t, t);
                            });
                            $('#btn-filter-all').click(function () {
                                $('#filter-date-from').val('');
                                $('#filter-date-to').val('');
                                loadDashboard('', '');
                            });
                        });
